{
  "command": "set -euo pipefail
TASK='.ypi/tasks/20260710-134919-修复-cpa-多账号导入覆盖并提示缺少-refresh-token'
node - <<'NODE'
const fs = require('fs');
const file = '.ypi/tasks/20260710-134919-修复-cpa-多账号导入覆盖并提示缺少-refresh-token/implement.md';
const source = fs.readFileSync(file, 'utf8');
const match = source.match(/```ypi-implementation-plan\n([\s\S]*?)\n```/);
if (!match) throw new Error('implementation plan block missing');
const plan = JSON.parse(match[1]);
if (plan.schemaVersion !== 2 || !Array.isArray(plan.subtasks) || plan.subtasks.length !== 6) throw new Error('plan contract invalid');
for (const task of plan.subtasks) {
  for (const key of ['id','title','phase','order','dependsOn','files','instructions','acceptance','validation','risks','parallelizable','localReview']) {
    if (!(key in task)) throw new Error(`${task.id} lacks ${key}`);
  }
}
console.log(`implementation plan JSON valid: ${plan.subtasks.length} subtasks`);
NODE
printf '\nArtifact headings:\n'
for f in brief prd ui design implement checks plan-review handoff; do printf '%-12s' "$f.md"; head -n 1 "$TASK/$f.md"; done
printf '\nTask files changed/untracked:\n'
git status --short -- "$TASK"
",
  "timeout": 20
}

{
  "command": "grep -n \"{{\" .ypi/tasks/20260710-134919-修复-cpa-多账号导入覆盖并提示缺少-refresh-token/cpa-refresh-token-risk-prototype.html"
}

{
  "command": "npx tsx -e 'import { convertOAuthAccountCredentialWithWarnings } from \"./lib/oauth-account-converters.ts\"; const converted = convertOAuthAccountCredentialWithWarnings(\"cpa\", [{ account_id: \"real-id\", access_token: \"access-one\", expired: \"2027-01-01T00:00:00Z\" }, { account_id: \"real-id\", access_token: \"access-two\", refresh_token: \"refresh-two\", expired: \"2027-01-01T00:00:00Z\" }]); if (converted.credentials.length !== 2 || converted.warnings.length !== 1 || converted.credentials[0].refresh !== \"\") throw new Error(\"CPA conversion contract failed\"); let threw = false; try { convertOAuthAccountCredentialWithWarnings(\"cpa\", [{ access_token: \"valid\", expired: \"2027-01-01T00:00:00Z\" }, { expired: \"2027-01-01T00:00:00Z\" }]); } catch { threw = true; } if (!threw) throw new Error(\"invalid batch was accepted\"); console.log(\"CPA conversion warning and validation contract passed\");'",
  "timeout": 120
}
